// Let's compute real numbers. Assume 100 million ops/second (a fast CPU).
//
// We'll print how long each complexity takes at n = 100,000.

const n = 100000;
const OPS_PER_SEC = 1e8;

function fmt(ops) {
  const sec = ops / OPS_PER_SEC;
  if (sec < 1)              return (sec * 1000).toFixed(2) + ' ms';
  if (sec < 60)             return sec.toFixed(2) + ' s';
  if (sec < 3600)           return (sec / 60).toFixed(1) + ' min';
  if (sec < 86400)          return (sec / 3600).toFixed(1) + ' h';
  if (sec < 86400 * 365)    return (sec / 86400).toFixed(1) + ' days';
  if (sec < 1e15)           return (sec / (86400 * 365)).toExponential(2) + ' years';
  return 'longer than the universe is old';
}

const log2n = Math.log2(n);
const rows = [
  ['O(1)',         1],
  ['O(log n)',     log2n],
  ['O(n)',         n],
  ['O(n log n)',   n * log2n],
  ['O(n²)',        n * n],
  ['O(n³)',        n * n * n],
  // O(2ⁿ) at n=100k would overflow — skip
];
console.log(`At n = ${n.toLocaleString()}, assuming ${OPS_PER_SEC.toExponential()} ops/sec:\n`);
for (const [label, ops] of rows) {
  console.log(`  ${label.padEnd(12)} ${fmt(ops)}`);
}

// Concrete demo: compare actual runtimes.
//
// Sum of an array three different ways. Same answer; very different speeds.

function makeArr(n) {
  return Array.from({ length: n }, (_, i) => i + 1);
}

// O(n) — single pass
function sumLinear(arr) {
  let total = 0;
  for (const x of arr) total += x;
  return total;
}

// O(n²) — nested for no good reason (demo)
function sumQuadratic(arr) {
  let total = 0;
  for (let i = 0; i < arr.length; i++) {
    for (let j = 0; j <= i; j++) {
      // pretend we have to revisit
      if (j === i) total += arr[i];
    }
  }
  return total;
}

// O(1) — closed-form! Gauss's trick: 1 + 2 + ... + n = n(n+1)/2
function sumConstant(n) {
  return (n * (n + 1)) / 2;
}

const n = 5000;
const arr = makeArr(n);

const t1 = performance.now();
sumLinear(arr);
const t2 = performance.now();
sumQuadratic(arr);
const t3 = performance.now();
sumConstant(n);
const t4 = performance.now();

console.log(`n = ${n}`);
console.log(`O(n)    sum: ${(t2 - t1).toFixed(2)} ms`);
console.log(`O(n²)   sum: ${(t3 - t2).toFixed(2)} ms`);
console.log(`O(1)    sum: ${(t4 - t3).toFixed(3)} ms`);
console.log('All three return the same answer.');

